        INSERT INTO STOCTCRL (
			   GATE_CD
			 , BUYER_CD
			 , CONT_NUM
			 , CONT_CNT
			 , FORM_NUM
			 , REG_DATE
			 , REG_USER_ID
			 , MOD_DATE
			 , MOD_USER_ID
			 , DEL_FLAG
			 , REQUIRE_FLAG
			 , FORM_SQ
			 , CONTRACT_TEXT_NUM
			 , FORM_CHECK_FLAG
			 , CONTRACT_TEXT
