			   #{ses.gateCd}
			 , #{ses.companyCd}
			 , #{CONT_NUM}
			 , #{CONT_CNT}
			 , #{REL_FORM_NUM}
			 , SYSDATE
			 , #{ses.userId}
			 , SYSDATE
			 , #{ses.userId}
			 , '0'
